// ==========================================
// 1. รับข้อมูลเข้า (Inputs)
// ==========================================
const item = $input.first().json; // ข้อมูลจาก Database (สินค้า, ราคา, คิว)

// ⚠️ สำคัญ: ตรวจสอบชื่อ Node เริ่มต้นของคุณให้ตรง (เช่น "Start" หรือ "Execute Workflow Trigger")
const inputData = $("INPUTDATA").first().json; 

const qty = parseInt(inputData.quantity); // จำนวนที่จะยิงจริง (แอดมินรวมยอดแถมมาให้แล้ว)
const userBalance = parseFloat(item.balance);

// ==========================================
// 2. ระบบเลือกเส้นทาง (Failover Logic)
// ==========================================
let finalServiceId = item.main_id;
let finalApiUrl = item.main_url;
let finalApiKey = item.main_key;
let finalProviderServiceId = item.main_pid;
let costPerUnit = parseFloat(item.main_cost);
let logRemark = inputData.remark || ""; // รับ Remark จากแอดมิน (ถ้ามี)

// เงื่อนไข: ถ้าคิวเกิน 10 และ มีตัวสำรองเตรียมไว้
if (parseInt(item.current_queue) > 20 && item.backup_id) {
    // สลับไปใช้ข้อมูลตัวสำรอง
    finalServiceId = item.backup_id;
    finalApiUrl = item.backup_url;
    finalApiKey = item.backup_key;
    finalProviderServiceId = item.backup_pid;
    costPerUnit = parseFloat(item.backup_cost);

    // บันทึก Log ต่อท้ายว่ามีการสลับเว็บ
    logRemark = (logRemark ? logRemark + " | " : "") + `Auto-Switch to Backup (Q: ${item.current_queue})`;
}

// ==========================================
// 3. คำนวณราคาขาย (Pricing Logic)
// ==========================================
let totalPrice = 0;

// 🔥 Case A: แอดมินระบุราคามาเอง (Custom Price)
// (เช่น แบ่ง 6 ลิงก์: ลิงก์แรกคิดเต็ม, ลิงก์ที่เหลือใส่ 0)
if (inputData.custom_price !== undefined && inputData.custom_price !== null && inputData.custom_price !== "") {
    totalPrice = parseFloat(inputData.custom_price);
} 
// 🛒 Case B: คำนวณตามตารางขั้นบันได (Normal Tier)
// (สำหรับลูกค้ากดหน้าเว็บ หรือแอดมินไม่ได้ระบุราคามา)
else {
    let finalPricePerUnit = parseFloat(item.sale_price); // ราคาเริ่มต้น (Fallback)

    if (item.price_tiers && item.price_tiers.length > 0) {
        // เรียงลำดับจาก มาก -> น้อย
        const sortedTiers = item.price_tiers.sort((a, b) => b.min_qty - a.min_qty);

        // วนลูปหาเรทราคาที่ตรงกับจำนวนที่สั่ง
        for (const tier of sortedTiers) {
            if (qty >= tier.min_qty) {
                finalPricePerUnit = parseFloat(tier.price);
                break;
            }
        }
    }
    // คำนวณราคา: (เรทต่อพัน * จำนวนพัน)
    totalPrice = finalPricePerUnit * (qty / 1000);
}

// ปัดเศษทศนิยม 2 ตำแหน่ง (กันเหนียว)
totalPrice = Math.round(totalPrice * 100) / 100;

// ==========================================
// 4. คำนวณต้นทุน (Cost Logic)
// ==========================================
// ต้นทุนคิดตามจริงเสมอ! (ต่อให้ขายลูกค้า 0 บาท แต่เราต้องจ่ายเว็บแม่)
let totalCost = costPerUnit * (qty / 1000);
totalCost = Math.round(totalCost * 100) / 100;

// ==========================================
// 5. ตรวจสอบความถูกต้อง (Validation)
// ==========================================
if (userBalance < totalPrice) {
    throw new Error(`เงินไม่พอครับ (ยอด ${totalPrice} / มี ${userBalance})`);
}

if (qty < item.min_qty || qty > item.max_qty) {
    // ยกเว้นกรณีเป็น Order แถม (custom_price = 0) อาจจะยอดน้อยกว่าขั้นต่ำได้ ถ้าเว็บแม่ยอมรับ
    finalServiceId = item.refill_service_id;
    finalApiUrl = item.refill_url;
    finalApiKey = item.refill_key;
    finalProviderServiceId = item.refill_pid;
    costPerUnit = parseFloat(item.refill_cost);

    if (totalPrice > 0) { 
        throw new Error(`จำนวนต้องอยู่ระหว่าง ${item.min_qty} - ${item.max_qty}`);

      logRemark = (logRemark ? logRemark + " | " : "") + `Auto-Switch to Backup (Q: ${item.current_queue})`;

    }

}

// ==========================================
// 6. ส่งค่าออกไป (Return Output)
// ==========================================
return {
    json: {
        // ข้อมูลสำหรับอ้างอิง
        user_db_id: item.user_db_id,
        link: inputData.link,
        start_count: inputData.start_count,
        qty: qty,                 // ยอดบันทึกใน DB ร้านเรา
        qty_to_send: qty,         // ยอดที่จะส่ง API (เท่ากัน เพราะแอดมินบวกมาแล้ว)
        dependency_order_id: inputData.dependency_order_id || null, // ส่งต่อการรอคิว


        // ข้อมูลสำหรับยิง API
        service_id: finalServiceId, // ID ที่เลือกใช้จริง (Main หรือ Backup)
        api_url: finalApiUrl,
        api_key: finalApiKey,
        provider_service_id: finalProviderServiceId,

        // ข้อมูลการเงิน
        total_price: totalPrice,
        cost_amount: totalCost,
        remark: logRemark
    }
};

