// รับข้อมูลจาก Node ก่อนหน้า (ไม่ว่าจะมาจากเส้นไหน)
const inputData = $input.first().json;
const status = $('Code').first().json.dependency_order_id === null ? 
                $('HTTP Request').first().json.order ? "PENDING"  : "FAIL" 
                : "QUEUED";

// จัด Format ให้เป็นมาตรฐานเดียวกัน ก่อนส่งกลับ Main
return {
    json: {
        // ถ้ามี id ส่ง id, ถ้าไม่มีให้เป็น null
        id: inputData.id || null, 

        // ส่งสถานะกลับไป (สำคัญมาก เพราะ Main ต้องรู้)
        status: status || 'UNKNOWN',
        link: inputData.link || null,
      start_count: $('Code').first().json.start_count,
      quantity: inputData.quantity || null,
        // ส่งข้อมูลอื่นๆ ที่ Main อาจจะอยากรู้
        service_id: inputData.service_id,
        remark: inputData.remark || "Process Finished"
    }
};

// รับข้อมูลจาก Node ก่อนหน้า (ไม่ว่าจะมาจากเส้นไหน)
const service_id = $input.first().json.service_id;

return {
    json: {
      input: $input.first(),
        user_id: $input.first().json.user_id,
        service_id: service_id,
        link: $input.first().json.link,
        quantity: $input.first().json.quantity,
        custom_price: $input.first().json.custom_price,
        wait_for_prev: $input.first().json.wait_for_prev,
        remark: $input.first().json.remark,
        dependency_order_id: $input.first().json.dependency_order_id || null,
    }
};

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  item.json.myNewField = 1;
}

return $input.all();
